query:
UPDATE raga_descriptions SET ragaName='Madhuwanti', trackTitleEn='Light and Shade', descriptionEn='Evokes the scorching heat of a Delhi summer. Played in 11/4 odd meter with different subdivisions.' WHERE id=1;
UPDATE raga_descriptions SET ragaName='Miyan ki Malhar', trackTitleEn='Desert Clouds', descriptionEn='The rainy season raga, bringing release after scorching heat. Strong polyrhythmic elements.' WHERE id=2;
UPDATE raga_descriptions SET ragaName='Purvi', trackTitleEn='Unknown Voyage', descriptionEn='Transformed through experimental note changes. An unknown journey with no fixed destination.' WHERE id=3;
UPDATE raga_descriptions SET ragaName='Kirwani', trackTitleEn='Fragmented Within', descriptionEn='Beats change bar by bar, different metres overlap. A non-settling feeling of fragmented self.' WHERE id=4;
UPDATE raga_descriptions SET ragaName='Yaman', trackTitleEn='Offering', descriptionEn='Repetitive phrases like a chant, invoking devotion. Minimalistic with a polyrhythmic approach.' WHERE id=5;
UPDATE raga_descriptions SET ragaName='Kedar', trackTitleEn='Journey to Kedarnath', descriptionEn='Inspired by the Himalayan pilgrimage site. Incorporates a bass line from the Esbjörn Svensson Trio.' WHERE id=6;
UPDATE raga_descriptions SET ragaName='Chandrakauns', trackTitleEn='Essence of Duality', descriptionEn='Five over four polyrhythm. Tonal centre shifts between B and C sections. The universe branching into many.' WHERE id=7;
UPDATE raga_descriptions SET ragaName='Bhatiyar', trackTitleEn='Dreams From the Past', descriptionEn='Memories and harmonic progression. A raga of longing and reflection.' WHERE id=8;
UPDATE raga_descriptions SET ragaName='Bhairavi', trackTitleEn='Run Away', descriptionEn='Fast pace composition with two different tonal centers — D and G. The album''s energetic finale.' WHERE id=9;

